from __future__ import annotations

from dataclasses import dataclass
from logging import Logger
from typing import Literal
from urllib.parse import urlparse

from server.config import BaseConfig, get_app_config
from server.utils.logging import get_app_logger

StartupRole = Literal["main", "game_server"]


@dataclass(frozen=True)
class StartupAlert:
    code: str
    message: str


def _is_blank(value: object) -> bool:
    return not str(value or "").strip()


def _is_production_config(config: BaseConfig) -> bool:
    return not bool(getattr(config, "TESTING", False)) and not bool(getattr(config, "IS_DEV", False))


def _is_wildcard_origin(origin: object) -> bool:
    return str(origin or "").strip() == "*"


def _is_local_url(raw_url: object) -> bool:
    parsed = urlparse(str(raw_url or "").strip())
    host = (parsed.hostname or "").lower()
    return host in {"localhost", "127.0.0.1", "0.0.0.0", "::1"}


def collect_startup_alerts(config: BaseConfig, *, role: StartupRole) -> list[StartupAlert]:
    """Return non-fatal startup safety alerts for risky runtime configuration."""
    alerts: list[StartupAlert] = []
    is_production = _is_production_config(config)

    if _is_blank(config.SECRET_KEY):
        alerts.append(
            StartupAlert(
                code="missing-secret-key",
                message="SECRET_KEY is not configured; session and CSRF signing is unsafe.",
            )
        )

    if _is_blank(config.JWT_SECRET_KEY):
        alerts.append(
            StartupAlert(
                code="missing-jwt-secret-key",
                message="JWT_SECRET_KEY is not configured; authentication tokens cannot be trusted.",
            )
        )

    if is_production and not bool(config.JWT_COOKIE_SECURE):
        alerts.append(
            StartupAlert(
                code="insecure-jwt-cookie",
                message="JWT_COOKIE_SECURE is false in production; JWT cookies may be sent over plaintext.",
            )
        )

    if is_production and any(_is_wildcard_origin(origin) for origin in config.CORS_ALLOWED_ORIGINS):
        alerts.append(
            StartupAlert(
                code="wildcard-cors-origin",
                message="CORS_ALLOWED_ORIGINS includes '*' in production; restrict browser origins explicitly.",
            )
        )

    if is_production:
        for setting_name in (
            "BACKEND_PUBLIC_BASE_URL",
            "FRONTEND_PUBLIC_BASE_URL",
            "GAME_WS_PUBLIC_BASE_URL",
            "CHAT_WS_PUBLIC_BASE_URL",
        ):
            if _is_local_url(getattr(config, setting_name, "")):
                alerts.append(
                    StartupAlert(
                        code=f"local-public-url-{setting_name.lower()}",
                        message=f"{setting_name} points at a local address in production.",
                    )
                )

    if role == "main" and is_production and _is_blank(config.GAME_SERVER_CREDENTIALS_JSON):
        alerts.append(
            StartupAlert(
                code="missing-game-server-credentials",
                message=(
                    "GAME_SERVER_CREDENTIALS_JSON is not configured; dedicated game servers "
                    "cannot authenticate with the control plane."
                ),
            )
        )

    if role == "game_server" and is_production:
        if _is_blank(config.GAME_SERVER_SELF_ID):
            alerts.append(
                StartupAlert(
                    code="missing-game-server-self-id",
                    message="GAME_SERVER_SELF_ID is not configured; this game server cannot register itself.",
                )
            )
        if _is_blank(config.GAME_SERVER_SELF_SIGNING_SECRET):
            alerts.append(
                StartupAlert(
                    code="missing-game-server-signing-secret",
                    message=(
                        "GAME_SERVER_SELF_SIGNING_SECRET is not configured; this game server "
                        "cannot authenticate heartbeats."
                    ),
                )
            )
        if _is_local_url(config.CONTROL_PLANE_INTERNAL_BASE_URL):
            alerts.append(
                StartupAlert(
                    code="local-control-plane-url",
                    message="CONTROL_PLANE_INTERNAL_BASE_URL points at a local address in production.",
                )
            )

    return alerts


def emit_startup_alerts(
    *,
    role: StartupRole,
    config: BaseConfig | None = None,
    logger: Logger | None = None,
) -> list[StartupAlert]:
    """Log startup safety alerts without making alert evaluation fatal."""
    alert_logger = logger or get_app_logger()
    try:
        runtime_config = config or get_app_config()
        alerts = collect_startup_alerts(runtime_config, role=role)
    except Exception as exc:
        alerts = [
            StartupAlert(
                code="startup-alert-evaluation-failed",
                message=f"Startup safety alert evaluation failed: {exc}",
            )
        ]

    for alert in alerts:
        alert_logger.warning(f"STARTUP SAFETY ALERT [{alert.code}] {alert.message}")

    return alerts

